"""Agora temos que definir unha función que nos permita comprobar se o verbo é conflitivo ou non: `check_vbo_conf`."""

def check_vbo_conf(vbo, conf, lang):
  # Para cada palabra na lista de palabras conflitivas
  for word in conf.loc[(conf['type']=='V') & (conf['lang']==lang)]['vbo']:
    # Se o verbo coincide coa palabra
    if(vbo == word):
      # Entón indicamos que é un verbo conflitivo
      return True
  # Se non se corresponde con ningún dos verbos da lista,
  #podemos concluir que non o é
  return False

